export interface AXLineChartOption {
  // Size and layout
  width?: number;
  height?: number;

  // Margins
  margins?: {
    top?: number;
    right?: number;
    bottom?: number;
    left?: number;
  };

  // Axis settings
  showXAxis?: boolean;
  showYAxis?: boolean;
  showGrid?: boolean;
  showVerticalGrid?: boolean;
  xAxisLabel?: string;
  yAxisLabel?: string;
  yAxisStartsAtZero?: boolean;
  axisPadding?: number;

  // Tooltip
  showTooltip?: boolean;

  // Line appearance
  lineWidth?: number;
  showPoints?: boolean;
  pointRadius?: number;
  smoothLine?: boolean;
  fillArea?: boolean;
  fillOpacity?: number;

  // Crosshair
  showCrosshair?: boolean;

  // Animation
  animationDuration?: number;
  animationEasing?: AXAnimationEasing;

  // Messages
  messages?: AXLineChartMessages;
}
